// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	var userInfo;
	var permissions;
	var defaultOU;
	var fieldPrefix = "u_organizational_user.";
	if (isLoading || newValue === '') {
		permissions = g_scratchpad.userRolesAndPermissions;
		_setMessages();
		return;
	} else {
		_changeMember();
	}
	// change all of these
	function _changeMember(){
		// STRY0050440 
		g_form.clearValue('u_organizational_user.is_task_administrator');
		// STRY0112585 - Task Executive- Update for New Member Form
		g_form.clearValue('u_organizational_user.is_task_executive');
		g_form.clearValue('u_organizational_user.is_tasker_application_administrator');
		g_form.clearValue('u_organizational_user.is_global_hierarchy_administrator');
		g_form.clearValue('u_organizational_user.can_manage_template_permissions');
		g_form.clearValue('u_organizational_user.can_manage_global_template');

		g_form.clearValue('u_organizational_user.has_personal_template_rights');
		g_form.clearValue('u_organizational_user.u_default_ou');

		var member_user = g_form.getValue('office_member');
		var userInfo  = new GlideAjax('ClientUserInfoScripts');
		userInfo.addParam('sysparm_name','getUserInfo');
		userInfo.addParam("user", member_user);
		// STRY0129039 - removed role parameter as it should be set one place for everywhere that we need the global role list

		userInfo.getXML(f_returnUserInfo);		
	}

	function f_returnUserInfo(response){
		var answer = response.responseXML.documentElement.getAttribute("answer");
		userInfo = JSON.parse(answer);
		permissions = userInfo.permissions;
		defaultOU = userInfo.defaultOU;
		for(var i=0; i<permissions.length; i++){
			var permission = permissions[i];
			var fieldName = fieldPrefix + permission.fieldName;
			if(g_form.getControl(fieldName)){
				g_form.setValue(fieldName, permission.hasRole);
			}
		}
		if(defaultOU.value && defaultOU.value != ''){
			// set default OU
			g_form.setValue(fieldPrefix + 'u_default_ou', defaultOU.value, defaultOU.displayValue);		
		} else {
			var currentOU = {};
			currentOU.value = g_form.getValue("discover_office_hierarchy");
			currentOU.displayValue = g_form.getDisplayValue("discover_office_hierarchy");

			g_form.setValue(fieldPrefix + 'u_default_ou', currentOU.value, currentOU.displayValue);		

		}

		_setMessages();
	}

	function _setMessages(){
		for(var i=0; i<permissions.length; i++){
			var permission = permissions[i];
			var fieldName = fieldPrefix + permission.fieldName;
			if(permission.fieldName && permission.fieldName != ''){
				// set the message for permission fields
				if(g_form.getControl(fieldName)){
					if(permission.hasRoleExplicitly){
						g_form.showFieldMsg(fieldName, 
											getMessage('Tasker - This user has been assigned the role explicitly (i.e., not assigned through group membership). Navigate to Tasker Administration - Groups Management and use the "lets fix it" link to move the user into the group.'),
											"warning");
					}
					if(permission.usesGroupsForRoles){
						if(!permission.groupSelected){
							g_form.showFieldMsg(fieldName, 
												getMessage("Tasker - Groups and Roles are not fully configured. Navigate to Tasker Administration - Groups Management and select a group for each role."),
												"warning");
							g_form.setDisabled(fieldName, true);
							g_form.setReadOnly(fieldName, true);
						} else if(!permission.groupHasRole){
							g_form.showFieldMsg(fieldName, 
												getMessage("Tasker - The Group is missing the role. Navigate to Tasker Administration - Groups Management and ensure all groups have a role applied."),
												"warning");
						}
					}
				}

			} else {
				// set the message for the member field
				if(permission.role == 'x_153465_discovert.tasker_user'){
					// is the member control on the form
					if(g_form.getControl('office_member')){
						if(permission.hasRoleExplicitly){
							g_form.showFieldMsg("office_member", 
													getMessage('Tasker - This user has been assigned the Task User role explicitly (i.e., not assigned through group membership). Navigate to Tasker Administration - Groups Management and use the "lets fix it" link to move the user into the group.'),
													"warning");
						}
						if(permission.usesGroupsForRoles){
							if(!permission.groupSelected){
								g_form.showFieldMsg("office_member", 
													getMessage("Tasker - Groups and Roles are not fully configured. Navigate to Tasker Administration - Groups Management and select a group for each role."),
													"warning");
								g_form.setDisabled("office_member", true);
								g_form.setReadOnly("office_member", true);
							} else if(!permission.groupHasRole){
								g_form.showFieldMsg("office_member", 
													getMessage("Tasker - The Group is missing the role. Navigate to Tasker Administration - Groups Management and ensure all groups have a role applied."),
													"warning");
							}
						}
					}
				}
			}
		}
		// disable member field this is not a new record
		if(!g_form.isNewRecord()){
			if(g_form.getControl('office_member')){
				g_form.setDisabled("office_member", true);
				g_form.setReadOnly("office_member", true);
			}
		}
	}
}
